challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The Home Subscriber Server (HSS) has exited, causing a complete failure of IMS services. The I-CSCF and S-CSCF cannot query the HSS for user location and authentication during call setup, leading to the observed SIP INVITE failures.",
      "primary_suspect_nf": "pyhss",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check all containers, looking for 'pyhss'",
          "expected_if_hypothesis_holds": "The 'pyhss' container status is 'exited' or 'down'.",
          "falsifying_observation": "The 'pyhss' container status is 'running' or 'up'.",
          "conflates_with": []
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container: 'pyhss', protocol: 'tcp'",
          "expected_if_hypothesis_holds": "No process is listening on the Diameter port (TCP/3868), or the check fails because the container is down.",
          "falsifying_observation": "A process is listening on the Diameter port (TCP/3868), indicating the HSS application is running.",
          "conflates_with": []
        },
        {
          "tool": "query_subscriber",
          "args_hint": "imsi: <any valid IMSI from the test environment>",
          "expected_if_hypothesis_holds": "The query fails or times out.",
          "falsifying_observation": "The query returns a valid subscriber profile, proving the HSS is fully operational.",
          "conflates_with": []
        }
      ],
      "notes": "Hypothesis h1 alleges a failure of the HSS, which is critical for the 'ims_registration' flow (steps 4, 6, 7) and 'vonr_call_setup' (step 6). These probes verify the HSS container, process, and application-level health."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The User Plane Function (UPF) is experiencing a critical fault, causing it to drop all downlink traffic. While uplink traffic is being received, no traffic is being forwarded to the RAN, resulting in a complete data plane outage.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds: 60",
          "expected_if_hypothesis_holds": "Non-zero packet rates arriving from the data network (e.g., n6_dl_packets_per_second > 0) but zero or near-zero rates for downlink traffic being forwarded to the RAN (n3_dl_packets_per_second == 0).",
          "falsifying_observation": "Non-zero packet rates for downlink traffic on the N3 interface (n3_dl_packets_per_second > 0), contradicting the claim that the UPF is dropping all downlink traffic.",
          "conflates_with": []
        },
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "Look for UPF-specific counters for N3 downlink packet discards or errors.",
          "expected_if_hypothesis_holds": "High or incrementing packet discard/error counters for the N3 downlink path, while N6 downlink ingress counters are incrementing.",
          "falsifying_observation": "Zero or non-incrementing discard/error counters for the N3 downlink path. This suggests the UPF is either successfully forwarding packets or not receiving them in the first place.",
          "conflates_with": []
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container: 'upf', port: 8805, protocol: 'udp'",
          "expected_if_hypothesis_holds": "A process is listening on the PFCP port (UDP/8805), indicating the N4 control plane interface is up. This isolates the failure to the data plane.",
          "falsifying_observation": "No process is listening on the PFCP port (UDP/8805). This would point to an N4 control plane failure as the root cause, rather than a pure data plane fault.",
          "conflates_with": []
        }
      ],
      "notes": "Hypothesis h2 alleges a data plane failure in the UPF. The 'pdu_session_establishment' flow creates the user plane, and media packets in 'vonr_call_setup' (step 12) depend on it. These probes check the UPF's data forwarding behavior (N6-in vs N3-out), internal error counters, and control plane status to isolate the fault."
    }
  ]
}

